import { getDetailedDescription } from './productDescriptions';
import { formatProductName } from '../utils/formatProductName';

function enhanceProductWithDescription(product: Product): Product {
  const detailedDescription = getDetailedDescription(product.cloudinaryId);
  return {
    ...product,
    name: formatProductName(product.cloudinaryId, product.subcategory),
    ...(detailedDescription && { description: detailedDescription }),
  };
}

// Renumber products that share the same (subcategory, baseName) to prevent duplicate display names.
// Within each group, products are sorted naturally by their filename so numbering matches visual order.
function deduplicateProductNames(products: Product[]): Product[] {
  const groups = new Map<string, Product[]>();

  for (const p of products) {
    const baseName = p.name.replace(/\s+\d+$/, '');
    const key = `${p.subcategory}|${baseName}`;
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key)!.push(p);
  }

  const result: Product[] = [];
  for (const [key, group] of groups) {
    const baseName = key.split('|').slice(1).join('|');
    const sorted = [...group].sort((a, b) => {
      const fa = a.cloudinaryId.split('/').pop() ?? '';
      const fb = b.cloudinaryId.split('/').pop() ?? '';
      return fa.localeCompare(fb, undefined, { numeric: true, sensitivity: 'base' });
    });
    sorted.forEach((p, i) => {
      result.push({ ...p, name: `${baseName} ${i + 1}` });
    });
  }

  return result;
}

export function getProductsByCategory(categorySlug: string): Product[] {
  const enhanced = ALL_PRODUCTS
    .filter(p => p.category === categorySlug)
    .map(enhanceProductWithDescription);
  return deduplicateProductNames(enhanced)
    .sort((a, b) => a.name.localeCompare(b.name, 'es', { numeric: true }));
}

export function getProductsBySubcategory(categorySlug: string, subcategorySlug: string): Product[] {
  if (subcategorySlug === 'all') {
    return getProductsByCategory(categorySlug);
  }
  const enhanced = ALL_PRODUCTS
    .filter(p => p.category === categorySlug && p.subcategory === subcategorySlug)
    .map(enhanceProductWithDescription);
  return deduplicateProductNames(enhanced)
    .sort((a, b) => a.name.localeCompare(b.name, 'es', { numeric: true }));
}

/**
 * Get product by ID
 */
export function getProductById(id: number): Product | undefined {
  const product = ALL_PRODUCTS.find(p => p.id === id);
  return product ? enhanceProductWithDescription(product) : undefined;
}

/**
 * Get product by Cloudinary ID
 */
export function getProductByCloudinaryId(cloudinaryId: string): Product | undefined {
  const product = ALL_PRODUCTS.find(p => p.cloudinaryId === cloudinaryId);
  return product ? enhanceProductWithDescription(product) : undefined;
}
